import torch.distributed as dist
import torch

def assert_params_in_sync(model, rank: int):
    """
    Broadcast rank 0's parameters to all ranks and check they match.
    Call at the start of training and after any suspicious operation.
    """
    for name, param in model.named_parameters():
        # Broadcast rank 0's version
        tensor = param.data.clone()
        dist.broadcast(tensor, src=0)
        if rank != 0:
            max_diff = (tensor - param.data).abs().max().item()
            if max_diff > 1e-6:
                raise RuntimeError(
                    f"Parameter '{name}' out of sync: "
                    f"rank {rank} max_diff={max_diff:.6e}"
                )
    if rank == 0:
        print("All parameters in sync across all ranks.")
